// Market risk radar — the SAME thresholds as server/risk_radar.py (single source of truth).
// Reads the CLOUD (Supabase market_prices), which the nightly n8n sync keeps fresh —
// so it works INDEPENDENTLY of whether the local Kist app is running.
// Requires n8n environment variables: SUPABASE_URL, SUPABASE_ANON_KEY.
const BASE = ($env.SUPABASE_URL || '').replace(/\/$/, '');
const KEY = $env.SUPABASE_ANON_KEY;
if (!BASE || !KEY) { throw new Error('Set SUPABASE_URL and SUPABASE_ANON_KEY in the n8n environment variables.'); }

async function last2(ticker) {
  const url = `${BASE}/rest/v1/market_prices?select=date,close&ticker=eq.${encodeURIComponent(ticker)}&order=date.desc&limit=2`;
  const rows = await this.helpers.httpRequest({ url, headers: { apikey: KEY, Authorization: `Bearer ${KEY}` }, json: true });
  const level = rows[0] ? rows[0].close : null;
  const prev = rows[1] ? rows[1].close : null;
  const chg = (level != null && prev) ? +(((level - prev) / prev) * 100).toFixed(2) : null;
  return { level, chg, asof: rows[0] ? rows[0].date : null };
}

const vix = await last2.call(this, '^VIX');
const gold = await last2.call(this, 'GC=F');
const oil = await last2.call(this, 'CL=F');
const usd = await last2.call(this, 'EURUSD=X');

// scores 0=calm, 1=elevated, 2=hot (identical to risk_radar.py)
let sVix = vix.level == null ? null : (vix.level < 18 ? 0 : vix.level <= 25 ? 1 : 2);
if (sVix != null && (vix.chg ?? 0) > 10) sVix = Math.min(2, sVix + 1);
const sGold = gold.chg == null ? null : (gold.chg > 2.5 ? 2 : gold.chg > 1.0 ? 1 : 0);
const sOil = oil.chg == null ? null : (Math.abs(oil.chg) > 6 ? 2 : Math.abs(oil.chg) > 3 ? 1 : 0);
const sUsd = usd.chg == null ? null : (usd.chg < -1.2 ? 2 : usd.chg < -0.5 ? 1 : 0);

const parts = [
  { label: 'VIX', s: sVix, v: vix.level, chg: vix.chg },
  { label: 'Gold', s: sGold, v: gold.level, chg: gold.chg },
  { label: 'WTI oil', s: sOil, v: oil.level, chg: oil.chg },
  { label: 'USD (EURUSD)', s: sUsd, v: usd.level, chg: usd.chg },
];
const missing = parts.filter((p) => p.s == null).map((p) => p.label);
const score = parts.reduce((a, p) => a + (p.s || 0), 0);
const state = score <= 1 ? '🟢 calm' : score <= 3 ? '🟡 elevated' : '🔴 hot';
const asof = [vix.asof, gold.asof, oil.asof, usd.asof].filter(Boolean).sort().pop();
const detail = parts.map((p) => `${p.label} ${p.v ?? '—'} (${p.chg ?? '—'}%/d, score ${p.s ?? '—'})`).join('; ');

// Alert only when 'hot' (score >= 4/8). Silence = calm/elevated.
return [{ json: { score, max: 8, state, hot: score >= 4, asof, detail, missing } }];
